-- Auto-generated by pg_pack (pgv)
-- 2026-03-28

CREATE SCHEMA IF NOT EXISTS pgv;

CREATE OR REPLACE FUNCTION pgv._parse_uri(p_uri text)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_uri text := p_uri;
  v_schema text;
  v_entity text;
  v_id text;
  v_method text;
  v_filter text;
  v_fragment text;
  v_path text;
  v_parts text[];
BEGIN
  -- Extract fragment (#schema)
  IF v_uri LIKE '%#%' THEN
    v_fragment := split_part(v_uri, '#', 2);
    v_uri := split_part(v_uri, '#', 1);
  END IF;

  -- Extract query params (?filter=...)
  IF v_uri LIKE '%?%' THEN
    FOR v_path IN
      SELECT pair FROM unnest(string_to_array(split_part(v_uri, '?', 2), '&')) AS pair
    LOOP
      IF v_path LIKE 'filter=%' THEN
        v_filter := substr(v_path, 8);
      END IF;
    END LOOP;
    v_uri := split_part(v_uri, '?', 1);
  END IF;

  -- Parse schema://path
  IF v_uri LIKE '%://%' THEN
    v_schema := split_part(v_uri, '://', 1);
    v_path := split_part(v_uri, '://', 2);
  ELSE
    v_path := v_uri;
  END IF;

  -- Handle empty schema (catalog)
  IF v_schema = '' THEN v_schema := NULL; END IF;

  -- Parse path: entity/id/method
  IF v_path IS NOT NULL AND v_path != '' THEN
    v_parts := string_to_array(v_path, '/');
    v_entity := v_parts[1];
    IF v_entity = '' THEN v_entity := NULL; END IF;
    IF array_length(v_parts, 1) >= 2 AND v_parts[2] != '' THEN
      v_id := v_parts[2];
    END IF;
    IF array_length(v_parts, 1) >= 3 AND v_parts[3] != '' THEN
      v_method := v_parts[3];
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'schema', v_schema,
    'entity', v_entity,
    'id', v_id,
    'method', v_method,
    'filter', v_filter,
    'fragment', v_fragment
  );
END;
$function$;
COMMENT ON FUNCTION pgv._parse_uri(text) IS 'Internal: parse CRUD URI into components (schema, entity, id, method, filter, fragment).';

CREATE OR REPLACE FUNCTION pgv._rsql_compare(p_lhs text, p_op text, p_val text, p_numeric boolean, p_type text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_list_items text[];
  v_quoted_items text[];
  v_val text := p_val;
BEGIN
  CASE p_op
    WHEN '==' THEN
      IF p_numeric THEN
        RETURN p_lhs || ' = ' || v_val::numeric;
      ELSIF p_type = 'bool' THEN
        RETURN p_lhs || ' = ' || v_val::boolean;
      ELSE
        RETURN p_lhs || ' = ' || quote_literal(v_val);
      END IF;

    WHEN '!=' THEN
      IF p_numeric THEN
        RETURN p_lhs || ' != ' || v_val::numeric;
      ELSE
        RETURN p_lhs || ' != ' || quote_literal(v_val);
      END IF;

    WHEN '>', '>=', '<', '<=' THEN
      IF p_numeric THEN
        RETURN p_lhs || ' ' || p_op || ' ' || v_val::numeric;
      ELSE
        RETURN p_lhs || ' ' || p_op || ' ' || quote_literal(v_val);
      END IF;

    WHEN '=in=', '=out=' THEN
      v_val := trim(BOTH '()' FROM v_val);
      v_list_items := string_to_array(v_val, ',');
      v_quoted_items := '{}';
      FOR i IN 1..array_length(v_list_items, 1) LOOP
        IF p_numeric THEN
          v_quoted_items := v_quoted_items || (trim(v_list_items[i])::numeric)::text;
        ELSE
          v_quoted_items := v_quoted_items || quote_literal(trim(v_list_items[i]));
        END IF;
      END LOOP;
      IF p_op = '=in=' THEN
        RETURN p_lhs || ' IN (' || array_to_string(v_quoted_items, ', ') || ')';
      ELSE
        RETURN p_lhs || ' NOT IN (' || array_to_string(v_quoted_items, ', ') || ')';
      END IF;

    WHEN '=like=' THEN
      RETURN p_lhs || ' LIKE ' || quote_literal(replace(v_val, '*', '%'));

    WHEN '=ilike=' THEN
      RETURN p_lhs || ' ILIKE ' || quote_literal(replace(v_val, '*', '%'));

    WHEN '=isnull=' THEN
      IF lower(v_val) = 'true' THEN
        RETURN p_lhs || ' IS NULL';
      ELSE
        RETURN p_lhs || ' IS NOT NULL';
      END IF;

    WHEN '=notnull=' THEN
      IF lower(v_val) = 'true' THEN
        RETURN p_lhs || ' IS NOT NULL';
      ELSE
        RETURN p_lhs || ' IS NULL';
      END IF;

    WHEN '=bt=' THEN
      v_val := trim(BOTH '()' FROM v_val);
      v_list_items := string_to_array(v_val, ',');
      IF array_length(v_list_items, 1) != 2 THEN
        RAISE EXCEPTION 'rsql: =bt= requires exactly 2 values, got %', array_length(v_list_items, 1);
      END IF;
      IF p_numeric THEN
        RETURN p_lhs || ' BETWEEN ' || trim(v_list_items[1])::numeric || ' AND ' || trim(v_list_items[2])::numeric;
      ELSE
        RETURN p_lhs || ' BETWEEN ' || quote_literal(trim(v_list_items[1])) || ' AND ' || quote_literal(trim(v_list_items[2]));
      END IF;

    ELSE
      RAISE EXCEPTION 'rsql: unsupported operator "%"', p_op;
  END CASE;
END;
$function$;
COMMENT ON FUNCTION pgv._rsql_compare(text,text,text,boolean,text) IS 'Internal helper: build SQL comparison fragment from RSQL operator, LHS expression, value, type info.';

CREATE OR REPLACE FUNCTION pgv.app_nav()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_result jsonb := '[]'::jsonb;
  v_mod record;
  v_schema text;
  v_brand text;
  v_items jsonb;
BEGIN
  FOR v_mod IN
    SELECT tm.module, tm.nav_group
      FROM workbench.tenant_module tm
     WHERE tm.active = true
       AND tm.module <> 'pgv'
     ORDER BY tm.sort_order, tm.module
  LOOP
    -- Resolve schema: find the namespace that has nav_items()
    SELECT n.nspname INTO v_schema
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
     WHERE p.proname = 'nav_items'
       AND n.nspname NOT LIKE '%\_qa' ESCAPE '\'
       AND n.nspname NOT LIKE '%\_ut' ESCAPE '\'
       AND n.nspname <> 'pgv'
       AND (n.nspname = v_mod.module OR v_mod.module LIKE n.nspname || '%')
     ORDER BY
       CASE WHEN n.nspname = v_mod.module THEN 0 ELSE 1 END
     LIMIT 1;

    IF v_schema IS NULL THEN
      CONTINUE;
    END IF;

    -- Get brand
    BEGIN
      EXECUTE format('SELECT %I.brand()', v_schema) INTO v_brand;
    EXCEPTION WHEN OTHERS THEN
      v_brand := initcap(v_mod.module);
    END;

    -- Get nav_items (handle both jsonb and TABLE return)
    BEGIN
      EXECUTE format('SELECT %I.nav_items()', v_schema) INTO v_items;
    EXCEPTION WHEN OTHERS THEN
      BEGIN
        EXECUTE format(
          'SELECT jsonb_agg(jsonb_build_object(''href'', href, ''label'', label, ''icon'', icon)) FROM %I.nav_items()',
          v_schema
        ) INTO v_items;
      EXCEPTION WHEN OTHERS THEN
        v_items := '[]'::jsonb;
      END;
    END;

    -- Enrich items with uri for entities
    IF v_items IS NOT NULL AND jsonb_typeof(v_items) = 'array' THEN
      SELECT coalesce(jsonb_agg(
        CASE WHEN item->>'entity' IS NOT NULL
          THEN item || jsonb_build_object('uri', v_schema || '://' || (item->>'entity'))
          ELSE item
        END
      ), '[]'::jsonb) INTO v_items
      FROM jsonb_array_elements(v_items) item;
    END IF;

    v_result := v_result || jsonb_build_object(
      'module', v_mod.module,
      'brand', v_brand,
      'schema', v_schema,
      'group', v_mod.nav_group,
      'items', coalesce(v_items, '[]'::jsonb)
    );
  END LOOP;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION pgv.app_nav() IS 'Aggregated navigation for all active tenant modules. Returns JSON array of modules with brand, schema, and nav items.';

CREATE OR REPLACE FUNCTION pgv.check_crud(p_schema text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_out text := 'check_crud: ' || p_schema || chr(10) || chr(10);
  v_rec record;
  v_entity text;
  v_has_create boolean;
  v_has_read boolean;
  v_has_list boolean;
  v_has_update boolean;
  v_has_delete boolean;
  v_errors int := 0;
  v_warnings int := 0;
  v_ok_count int := 0;
  v_crud_count int := 0;
  v_line text;
  v_issues text[];
  v_fn_rec record;
BEGIN
  -- 1. Check overloads (same proname, multiple entries)
  FOR v_rec IN
    SELECT p.proname, count(*) AS cnt
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = p_schema
    GROUP BY p.proname
    HAVING count(*) > 1
    ORDER BY p.proname
  LOOP
    v_out := v_out || '✗ overload: ' || v_rec.proname || ' (' || v_rec.cnt || ' versions)' || chr(10);
    v_errors := v_errors + 1;
  END LOOP;

  -- 2. Naming warnings (_load, _get, _find, _insert, _remove)
  FOR v_rec IN
    SELECT p.proname
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = p_schema
      AND (p.proname LIKE '%_load' OR p.proname LIKE '%_get'
        OR p.proname LIKE '%_find' OR p.proname LIKE '%_insert'
        OR p.proname LIKE '%_remove')
    ORDER BY p.proname
  LOOP
    v_out := v_out || '⚠ naming: ' || v_rec.proname || ' — consider renaming to CRUD convention (_create/_read/_list/_update/_delete)' || chr(10);
    v_warnings := v_warnings + 1;
  END LOOP;

  -- 3. Per-entity CRUD analysis
  -- Discover entities from table names
  FOR v_rec IN
    SELECT c.relname
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = p_schema AND c.relkind = 'r'
    ORDER BY c.relname
  LOOP
    v_entity := v_rec.relname;
    v_issues := '{}';

    -- Check which CRUD functions exist
    SELECT EXISTS(SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = p_schema AND p.proname = v_entity || '_create') INTO v_has_create;
    SELECT EXISTS(SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = p_schema AND (p.proname = v_entity || '_read' OR p.proname = v_entity || '_load')) INTO v_has_read;
    SELECT EXISTS(SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = p_schema AND p.proname = v_entity || '_list') INTO v_has_list;
    SELECT EXISTS(SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = p_schema AND p.proname = v_entity || '_update') INTO v_has_update;
    SELECT EXISTS(SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = p_schema AND p.proname = v_entity || '_delete') INTO v_has_delete;

    IF NOT v_has_create AND NOT v_has_read AND NOT v_has_list AND NOT v_has_delete THEN
      v_out := v_out || '⚠ ' || v_entity || ' — no CRUD functions' || chr(10);
      v_warnings := v_warnings + 1;
      CONTINUE;
    END IF;

    -- Build status line
    v_line := '';
    IF v_has_create THEN v_line := v_line || 'create '; v_crud_count := v_crud_count + 1; END IF;
    IF v_has_read THEN v_line := v_line || 'read '; v_crud_count := v_crud_count + 1; END IF;
    IF v_has_list THEN v_line := v_line || 'list '; v_crud_count := v_crud_count + 1; END IF;
    IF v_has_update THEN v_line := v_line || 'update '; v_crud_count := v_crud_count + 1; END IF;
    IF v_has_delete THEN v_line := v_line || 'delete '; v_crud_count := v_crud_count + 1; END IF;

    -- Check return types
    FOR v_fn_rec IN
      SELECT p.proname, t.typname AS rettype, p.proretset
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      JOIN pg_type t ON t.oid = p.prorettype
      WHERE n.nspname = p_schema
        AND p.proname IN (
          v_entity || '_create', v_entity || '_read', v_entity || '_load',
          v_entity || '_list', v_entity || '_update', v_entity || '_delete'
        )
    LOOP
      IF v_fn_rec.proname LIKE '%_delete' AND v_fn_rec.rettype != 'bool' THEN
        v_issues := v_issues || (v_fn_rec.proname || ' should return bool, returns ' || v_fn_rec.rettype);
        v_errors := v_errors + 1;
      END IF;
    END LOOP;

    IF array_length(v_issues, 1) > 0 THEN
      v_out := v_out || '✗ ' || v_entity || ' — ' || trim(v_line) || ' | ' || array_to_string(v_issues, '; ') || chr(10);
    ELSE
      v_out := v_out || '✓ ' || v_entity || ' — ' || trim(v_line) || chr(10);
      v_ok_count := v_ok_count + 1;
    END IF;
  END LOOP;

  -- Summary
  v_out := v_out || chr(10);
  IF v_errors = 0 AND v_warnings = 0 THEN
    v_out := v_out || 'ok (' || v_ok_count || ' entities, ' || v_crud_count || ' CRUD functions)';
  ELSE
    IF v_errors > 0 THEN v_out := v_out || v_errors || ' error(s)'; END IF;
    IF v_warnings > 0 THEN
      IF v_errors > 0 THEN v_out := v_out || ', '; END IF;
      v_out := v_out || v_warnings || ' warning(s)';
    END IF;
  END IF;

  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION pgv.check_crud(text) IS 'Audit CRUD convention compliance for a schema: overloads, naming, return types, entity existence.';

CREATE OR REPLACE FUNCTION pgv.esc(p_text text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT replace(replace(replace(replace(replace(
    coalesce(p_text, ''),
    '&', '&amp;'), '<', '&lt;'), '>', '&gt;'), '"', '&quot;'), '''', '&#39;');
$function$;

CREATE OR REPLACE FUNCTION pgv.filesize(p_bytes bigint)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_bytes IS NULL THEN '-'
    WHEN p_bytes < 1024 THEN p_bytes || ' B'
    WHEN p_bytes < 1048576 THEN round(p_bytes / 1024.0, 1) || ' KB'
    WHEN p_bytes < 1073741824 THEN round(p_bytes / 1048576.0, 1) || ' MB'
    ELSE round(p_bytes / 1073741824.0, 1) || ' GB'
  END;
$function$;

CREATE OR REPLACE FUNCTION pgv.html_audit(p_schema text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_rec record;
  v_rows text := '';
  v_warn int := 0;
  v_ok int := 0;
  v_rules jsonb;
BEGIN
  -- Rules: tag pattern -> primitive, with exclusion if primitive is also called
  -- excl: if present, skip match when this pattern is also found (avoids false positives)
  v_rules := '[
    {"tag":"<template data-toast",  "prim":"pgv.toast()",          "call":"pgv.toast("},
    {"tag":"<template data-redirect","prim":"pgv.redirect()",     "call":"pgv.redirect("},
    {"tag":"<form data-rpc",        "prim":"pgv.form()",          "call":"pgv.form("},
    {"tag":"<button data-rpc",      "prim":"pgv.action()",        "call":"pgv.action("},
    {"tag":"<details>",             "prim":"pgv.accordion()",     "call":"pgv.accordion("},
    {"tag":"<select>",              "prim":"pgv.sel()",           "call":"pgv.sel("},
    {"tag":"<dl>",                  "prim":"pgv.dl()",            "call":"pgv.dl("},
    {"tag":"<article",              "prim":"pgv.card()",          "call":"pgv.card("},
    {"tag":"<input ",               "prim":"pgv.input()",         "call":"pgv.input(",         "excl":"type=\\\"hidden\\\""},
    {"tag":"type=\\\"checkbox\\\"","prim":"pgv.checkbox()",     "call":"pgv.checkbox("},
    {"tag":"type=\\\"radio\\\"",   "prim":"pgv.radio()",         "call":"pgv.radio("},
    {"tag":"<textarea",             "prim":"pgv.textarea()",      "call":"pgv.textarea("},
    {"tag":"<progress",             "prim":"pgv.progress()",      "call":"pgv.progress("},
    {"tag":"<table",                "prim":"pgv.md_table()",      "call":"pgv.md_table("},
    {"tag":"pgv-alert",             "prim":"pgv.alert()",         "call":"pgv.alert("},
    {"tag":"pgv-badge",             "prim":"pgv.badge()",         "call":"pgv.badge("},
    {"tag":"pgv-stat",              "prim":"pgv.stat()",          "call":"pgv.stat("},
    {"tag":"pgv-grid",              "prim":"pgv.grid()",          "call":"pgv.grid("},
    {"tag":"pgv-tabs",              "prim":"pgv.tabs()",          "call":"pgv.tabs("},
    {"tag":"pgv-breadcrumb",        "prim":"pgv.breadcrumb()",    "call":"pgv.breadcrumb("},
    {"tag":"pgv-empty",             "prim":"pgv.empty()",         "call":"pgv.empty("},
    {"tag":"pgv-timeline",          "prim":"pgv.timeline()",      "call":"pgv.timeline("},
    {"tag":"pgv-workflow",          "prim":"pgv.workflow()",      "call":"pgv.workflow("},
    {"tag":"pgv-avatar",            "prim":"pgv.avatar()",        "call":"pgv.avatar("},
    {"tag":"selectSearch",          "prim":"pgv.select_search()", "call":"pgv.select_search("},
    {"tag":"x-data=\\\"lazy\\\"","prim":"pgv.lazy()",           "call":"pgv.lazy("}
  ]'::jsonb;

  FOR v_rec IN
    WITH fn_bodies AS (
      SELECT p.proname, p.prosrc AS def
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema
        AND (p.proname LIKE 'get_%' OR p.proname LIKE 'post_%')
    ),
    rule_checks AS (
      SELECT f.proname,
             r->>'tag' AS tag,
             r->>'prim' AS prim,
             f.def LIKE '%' || (r->>'tag') || '%' AS has_tag,
             f.def LIKE '%' || (r->>'call') || '%' AS has_call,
             CASE WHEN r->>'excl' IS NOT NULL
                  THEN f.def LIKE '%' || (r->>'excl') || '%'
                  ELSE false END AS has_excl
      FROM fn_bodies f
      CROSS JOIN jsonb_array_elements(v_rules) AS r
    )
    SELECT proname, tag, prim
    FROM rule_checks
    WHERE has_tag AND NOT has_call AND NOT has_excl
    ORDER BY proname, tag
  LOOP
    v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning')
      || ' | ' || v_rec.proname || '()'
      || ' | `' || pgv.esc(v_rec.tag) || '`'
      || ' | ' || v_rec.prim || ' |' || chr(10);
    v_warn := v_warn + 1;
  END LOOP;

  IF v_warn = 0 THEN
    v_ok := 1;
  END IF;

  RETURN pgv.dl(
    'HTML audit', p_schema,
    'Bilan',
      CASE WHEN v_warn > 0 THEN pgv.badge(v_warn || ' raw HTML', 'warning') || ' ' ELSE '' END
      || CASE WHEN v_ok > 0 THEN pgv.badge('clean', 'success') ELSE '' END)
    || '<md>' || chr(10)
    || '| Niveau | Source | Tag | Primitive |' || chr(10)
    || '|--------|--------|-----|-----------|' || chr(10)
    || v_rows
    || '</md>';
END;
$function$;
COMMENT ON FUNCTION pgv.html_audit(text) IS 'Scan schema functions for raw HTML that should use pgv.* primitives. Returns markdown report.';

CREATE OR REPLACE FUNCTION pgv.i18n_bundle(p_lang text DEFAULT 'fr'::text)
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT coalesce(jsonb_object_agg(key, value), '{}'::jsonb)
  FROM pgv.i18n
  WHERE lang = p_lang;
$function$;
COMMENT ON FUNCTION pgv.i18n_bundle(text) IS 'Returns all i18n translations as a flat {key: value} JSON object for a given language.';

CREATE OR REPLACE FUNCTION pgv.i18n_seed()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO pgv.i18n (lang, key, value) VALUES
    ('fr', 'pgv.issue_reported', 'Signalement envoyé, merci !'),
    ('fr', 'pgv.page_not_found', 'Page non trouvee'),
    ('fr', 'pgv.path_not_found', 'Le chemin %s n''existe pas.'),
    ('fr', 'pgv.error', 'Erreur'),
    ('fr', 'pgv.invalid_param', 'Parametre invalide'),
    ('fr', 'pgv.internal_error', 'Erreur interne'),
    ('fr', 'pgv.unexpected_error', 'Une erreur inattendue est survenue.'),
    ('fr', 'pgv.filter', 'Filtrer'),
    ('fr', 'pgv.filter_clear', 'Effacer'),
    ('fr', 'pgv.table_next', 'Suivant'),
    ('fr', 'pgv.table_prev', 'Précédent'),
    ('fr', 'pgv.table_empty', 'Aucun résultat'),
    ('fr', 'pgv.table_loading', 'Chargement…'),
    ('fr', 'pgv.table_search', 'Rechercher…'),
    ('fr', 'pgv.print', 'Télécharger SVG'),
    ('fr', 'app.group_main', 'Principal'),
    ('fr', 'app.group_commercial', 'Commercial'),
    ('fr', 'app.group_operations', 'Opérations'),
    ('fr', 'app.group_finance', 'Finance'),
    ('fr', 'app.group_team', 'Équipe'),
    ('fr', 'app.group_admin', 'Administration'),
    ('fr', 'app.search', 'Rechercher...')
  ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
END;
$function$;
COMMENT ON FUNCTION pgv.i18n_seed() IS 'Seed French translations for pgv framework strings into pgv.i18n table.';

CREATE OR REPLACE FUNCTION pgv.md_esc(p_text text, p_max_len integer DEFAULT 80)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT left(
    replace(replace(replace(pgv.esc(p_text), '|', '\|'), E'\n', ' '), E'\r', ''),
    p_max_len
  );
$function$;
COMMENT ON FUNCTION pgv.md_esc(text,integer) IS 'Escape text for safe use in markdown table cells — escapes pipes, newlines, HTML, and truncates';

CREATE OR REPLACE FUNCTION pgv.money(p_amount numeric)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT to_char(p_amount, 'FM999 999 990D00') || ' EUR';
$function$;

CREATE OR REPLACE FUNCTION pgv.nav_schema()
 RETURNS json
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '{
    "type": "object",
    "required": ["module", "brand", "schema", "group", "items"],
    "properties": {
      "module": { "type": "string" },
      "brand": { "type": "string" },
      "schema": { "type": "string" },
      "group": { "type": ["string", "null"] },
      "items": {
        "type": "array",
        "items": {
          "type": "object",
          "required": ["label"],
          "properties": {
            "label": { "type": "string" },
            "href": { "type": "string" },
            "icon": { "type": ["string", "null"] },
            "entity": { "type": "string" },
            "uri": { "type": "string", "pattern": "^[a-z_]+://[a-z_]+$" }
          },
          "if": { "required": ["entity"] },
          "then": { "required": ["entity", "uri"] }
        }
      }
    }
  }'::json;
$function$;
COMMENT ON FUNCTION pgv.nav_schema() IS 'JSON Schema for a single module entry in app_nav() response. Validates module, brand, schema, group, items structure.';

CREATE OR REPLACE FUNCTION pgv.check_nav()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_nav jsonb;
  v_mod jsonb;
  v_out text := 'check_nav:' || chr(10) || chr(10);
  v_ok int := 0;
  v_err int := 0;
BEGIN
  v_nav := pgv.app_nav();

  FOR v_mod IN SELECT * FROM jsonb_array_elements(v_nav) LOOP
    IF jsonb_matches_schema(pgv.nav_schema(), v_mod) THEN
      v_out := v_out || '✓ ' || (v_mod->>'module') || chr(10);
      v_ok := v_ok + 1;
    ELSE
      v_out := v_out || '✗ ' || (v_mod->>'module') || ' — schema validation failed' || chr(10);
      v_err := v_err + 1;
    END IF;
  END LOOP;

  v_out := v_out || chr(10);
  IF v_err = 0 THEN
    v_out := v_out || 'ok (' || v_ok || ' modules)';
  ELSE
    v_out := v_out || v_err || ' error(s), ' || v_ok || ' ok';
  END IF;

  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION pgv.check_nav() IS 'Validate app_nav() response: each module entry checked against nav_schema(). Returns report text.';

CREATE OR REPLACE FUNCTION pgv.rsql_to_where(p_filter text, p_schema text, p_table text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_or_parts text[];
  v_or_part text;
  v_and_parts text[];
  v_and_part text;
  v_or_clauses text[] := '{}';
  v_and_clauses text[];
  v_field text;
  v_op text;
  v_val text;
  v_col text;
  v_col_type text;
  v_sql_part text;
  v_match text[];
  v_is_numeric boolean;
  v_path text[];
  v_jsonb_path text;
  v_fk_target_schema text;
  v_fk_target_table text;
  v_fk_src_col text;
  v_fk_tgt_col text;
  v_fk_filter_col text;
  v_fk_col_type text;
BEGIN
  IF p_filter IS NULL OR trim(p_filter) = '' THEN
    RETURN 'true';
  END IF;

  v_val := p_filter;
  WHILE v_val ~ '\([^)]*,[^)]*\)' LOOP
    v_val := regexp_replace(v_val, '\(([^)]*),([^)]*)\)', '(\1' || chr(1) || '\2)', 'g');
  END LOOP;

  v_or_parts := string_to_array(v_val, ',');

  FOREACH v_or_part IN ARRAY v_or_parts LOOP
    v_and_clauses := '{}';
    v_and_parts := string_to_array(v_or_part, ';');

    FOREACH v_and_part IN ARRAY v_and_parts LOOP
      v_match := regexp_match(v_and_part, '^([a-zA-Z_][a-zA-Z0-9_.]*)(==|!=|>=|<=|>|<|=in=|=out=|=like=|=ilike=|=isnull=|=notnull=|=bt=)(.+)$');

      IF v_match IS NULL THEN
        RAISE EXCEPTION 'rsql: invalid expression "%"', v_and_part;
      END IF;

      v_field := v_match[1];
      v_op := v_match[2];
      v_val := replace(v_match[3], chr(1), ',');

      v_path := string_to_array(v_field, '.');
      v_col := v_path[1];

      -- Look up column type
      SELECT t.typname INTO v_col_type
      FROM pg_attribute a
      JOIN pg_class c ON c.oid = a.attrelid
      JOIN pg_namespace n ON n.oid = c.relnamespace
      JOIN pg_type t ON t.oid = a.atttypid
      WHERE n.nspname = p_schema AND c.relname = p_table
        AND a.attname = v_col AND a.attnum > 0 AND NOT a.attisdropped;

      -- v3: FK relation traversal (first segment = related table name)
      IF v_col_type IS NULL AND array_length(v_path, 1) > 1 THEN
        SELECT n2.nspname, c2.relname, a1.attname, a2.attname
        INTO v_fk_target_schema, v_fk_target_table, v_fk_src_col, v_fk_tgt_col
        FROM pg_constraint con
        JOIN pg_class c1 ON c1.oid = con.conrelid
        JOIN pg_namespace n1 ON n1.oid = c1.relnamespace
        JOIN pg_class c2 ON c2.oid = con.confrelid
        JOIN pg_namespace n2 ON n2.oid = c2.relnamespace
        JOIN pg_attribute a1 ON a1.attrelid = con.conrelid AND a1.attnum = con.conkey[1]
        JOIN pg_attribute a2 ON a2.attrelid = con.confrelid AND a2.attnum = con.confkey[1]
        WHERE con.contype = 'f'
          AND n1.nspname = p_schema AND c1.relname = p_table
          AND c2.relname = v_col;

        IF v_fk_target_schema IS NULL THEN
          RAISE EXCEPTION 'rsql: "%" is not a column or FK relation in %.%', v_col, p_schema, p_table;
        END IF;

        v_fk_filter_col := v_path[2];
        SELECT t.typname INTO v_fk_col_type
        FROM pg_attribute a
        JOIN pg_class c ON c.oid = a.attrelid
        JOIN pg_namespace n ON n.oid = c.relnamespace
        JOIN pg_type t ON t.oid = a.atttypid
        WHERE n.nspname = v_fk_target_schema AND c.relname = v_fk_target_table
          AND a.attname = v_fk_filter_col AND a.attnum > 0 AND NOT a.attisdropped;

        IF v_fk_col_type IS NULL THEN
          RAISE EXCEPTION 'rsql: column "%" does not exist in %.%', v_fk_filter_col, v_fk_target_schema, v_fk_target_table;
        END IF;

        v_is_numeric := v_fk_col_type IN ('int2', 'int4', 'int8', 'float4', 'float8', 'numeric');
        v_sql_part := pgv._rsql_compare(format('%I', v_fk_filter_col), v_op, v_val, v_is_numeric, v_fk_col_type);
        v_sql_part := format('EXISTS (SELECT 1 FROM %I.%I WHERE %I = %I.%I AND %s)',
          v_fk_target_schema, v_fk_target_table,
          v_fk_tgt_col, p_table, v_fk_src_col, v_sql_part);

        v_and_clauses := v_and_clauses || v_sql_part;
        CONTINUE;
      END IF;

      IF v_col_type IS NULL THEN
        RAISE EXCEPTION 'rsql: column "%" does not exist in %.%', v_col, p_schema, p_table;
      END IF;

      -- v2: JSONB traversal
      IF array_length(v_path, 1) > 1 AND v_col_type = 'jsonb' THEN
        v_jsonb_path := format('%I', v_col);
        FOR i IN 2..array_length(v_path, 1) LOOP
          IF i = array_length(v_path, 1) THEN
            IF v_path[i] ~ '^\d+$' THEN
              v_jsonb_path := v_jsonb_path || '->>' || v_path[i];
            ELSE
              v_jsonb_path := v_jsonb_path || '->>''' || v_path[i] || '''';
            END IF;
          ELSE
            IF v_path[i] ~ '^\d+$' THEN
              v_jsonb_path := v_jsonb_path || '->' || v_path[i];
            ELSE
              v_jsonb_path := v_jsonb_path || '->''' || v_path[i] || '''';
            END IF;
          END IF;
        END LOOP;

        v_sql_part := pgv._rsql_compare(v_jsonb_path, v_op, v_val, false, 'text');
        v_and_clauses := v_and_clauses || v_sql_part;
        CONTINUE;
      END IF;

      -- Simple column
      v_is_numeric := v_col_type IN ('int2', 'int4', 'int8', 'float4', 'float8', 'numeric');
      v_sql_part := pgv._rsql_compare(format('%I', v_col), v_op, v_val, v_is_numeric, v_col_type);
      v_and_clauses := v_and_clauses || v_sql_part;
    END LOOP;

    v_or_clauses := v_or_clauses || ('(' || array_to_string(v_and_clauses, ' AND ') || ')');
  END LOOP;

  IF array_length(v_or_clauses, 1) = 1 THEN
    RETURN substr(v_or_clauses[1], 2, length(v_or_clauses[1]) - 2);
  END IF;

  RETURN array_to_string(v_or_clauses, ' OR ');
END;
$function$;
COMMENT ON FUNCTION pgv.rsql_to_where(text,text,text) IS 'Parse RSQL filter into safe SQL WHERE. Supports jsonb dot notation (v2) and FK relation traversal (v3).';

CREATE OR REPLACE FUNCTION pgv.rsql_validate(p_filter text)
 RETURNS boolean
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_filter text;
  v_parts text[];
  v_part text;
  v_atoms text[];
  v_atom text;
BEGIN
  IF p_filter IS NULL OR trim(p_filter) = '' THEN
    RETURN true;
  END IF;

  -- Protect commas inside parentheses
  v_filter := p_filter;
  WHILE v_filter ~ '\([^)]*,[^)]*\)' LOOP
    v_filter := regexp_replace(v_filter, '\(([^)]*),([^)]*)\)', '(\1' || chr(1) || '\2)', 'g');
  END LOOP;

  -- Split by , (OR)
  v_parts := string_to_array(v_filter, ',');

  FOREACH v_part IN ARRAY v_parts LOOP
    -- Split by ; (AND)
    v_atoms := string_to_array(v_part, ';');
    FOREACH v_atom IN ARRAY v_atoms LOOP
      IF NOT v_atom ~ '^[a-zA-Z_][a-zA-Z0-9_]*(==|!=|>=|<=|>|<|=in=|=out=|=like=|=ilike=|=isnull=|=notnull=|=bt=).+$' THEN
        RETURN false;
      END IF;
    END LOOP;
  END LOOP;

  RETURN true;
END;
$function$;
COMMENT ON FUNCTION pgv.rsql_validate(text) IS 'Validate RSQL filter syntax without executing. Returns true if valid, false otherwise.';

CREATE OR REPLACE FUNCTION pgv.schema_catalog()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT coalesce(jsonb_agg(row ORDER BY row->>'schema'), '[]')
  FROM (
    SELECT jsonb_build_object(
      'schema', n.nspname,
      'comment', d.description,
      'tables', (
        SELECT count(*) FROM pg_class c
        WHERE c.relnamespace = n.oid AND c.relkind = 'r'
      ),
      'functions', (
        SELECT count(*) FROM pg_proc p
        WHERE p.pronamespace = n.oid
      )
    ) AS row
    FROM pg_namespace n
    LEFT JOIN pg_description d ON d.objoid = n.oid AND d.classoid = 'pg_namespace'::regclass
    WHERE n.nspname NOT LIKE 'pg_%'
      AND n.nspname NOT IN ('information_schema', 'public', 'extensions')
      AND n.nspname NOT LIKE '%_ut'
      AND n.nspname NOT LIKE '%_qa'
      AND n.nspname NOT LIKE '%_it'
  ) sub;
$function$;
COMMENT ON FUNCTION pgv.schema_catalog() IS 'Returns overview of all application schemas: name, table count, function count, comment. Excludes system/test/qa schemas.';

CREATE OR REPLACE FUNCTION pgv.schema_comments(p_schema text)
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  WITH schema_comment AS (
    SELECT 'SCHEMA ' || p_schema || ': ' || coalesce(d.description, '(none)')
    FROM pg_namespace n
    LEFT JOIN pg_description d ON d.objoid = n.oid AND d.classoid = 'pg_namespace'::regclass
    WHERE n.nspname = p_schema
  ),
  table_comments AS (
    SELECT c.relname AS tbl,
           d.description AS tbl_comment,
           a.attname AS col,
           cd.description AS col_comment
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    LEFT JOIN pg_description d ON d.objoid = c.oid AND d.objsubid = 0
    LEFT JOIN pg_attribute a ON a.attrelid = c.oid AND a.attnum > 0 AND NOT a.attisdropped
    LEFT JOIN pg_description cd ON cd.objoid = c.oid AND cd.objsubid = a.attnum
    WHERE n.nspname = p_schema AND c.relkind = 'r'
    ORDER BY c.relname, a.attnum
  ),
  formatted AS (
    SELECT string_agg(line, chr(10)) AS body
    FROM (
      SELECT '## ' || tbl
        || chr(10) || 'table: ' || coalesce(tbl_comment, '(no comment)')
        || chr(10) || string_agg(
          '  ' || col || ': ' || coalesce(col_comment, '-'),
          chr(10) ORDER BY col
        ) AS line
      FROM table_comments
      GROUP BY tbl, tbl_comment
      ORDER BY tbl
    ) sub
  )
  SELECT (SELECT * FROM schema_comment) || chr(10) || chr(10) || coalesce(f.body, '(no tables)')
  FROM formatted f;
$function$;
COMMENT ON FUNCTION pgv.schema_comments(text) IS 'Lists all COMMENT ON for a schema (tables + columns). Text format for coverage review.';

CREATE OR REPLACE FUNCTION pgv.schema_discover(p_schema text)
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT coalesce(jsonb_agg(tbl ORDER BY tbl->>'table'), '[]')
  FROM (
    SELECT jsonb_build_object(
      'table', c.relname,
      'comment', d.description,
      'rows', c.reltuples::bigint,
      'columns', (
        SELECT coalesce(jsonb_agg(
          jsonb_build_object(
            'name', col.column_name,
            'type', col.udt_name || CASE
              WHEN col.character_maximum_length IS NOT NULL THEN '(' || col.character_maximum_length || ')'
              ELSE '' END,
            'nullable', col.is_nullable = 'YES',
            'default', col.column_default,
            'comment', cd.description
          ) ORDER BY col.ordinal_position
        ), '[]')
        FROM information_schema.columns col
        LEFT JOIN pg_attribute a ON a.attrelid = c.oid AND a.attname = col.column_name::name
        LEFT JOIN pg_description cd ON cd.objoid = c.oid AND cd.objsubid = a.attnum
        WHERE col.table_schema = p_schema AND col.table_name = c.relname
      ),
      'foreign_keys', (
        SELECT coalesce(jsonb_agg(
          jsonb_build_object(
            'column', kcu.column_name,
            'references', ccu.table_schema || '.' || ccu.table_name || '.' || ccu.column_name
          )
        ), '[]')
        FROM information_schema.table_constraints tc
        JOIN information_schema.key_column_usage kcu
          ON kcu.constraint_name = tc.constraint_name AND kcu.table_schema = tc.table_schema
        JOIN information_schema.constraint_column_usage ccu
          ON ccu.constraint_name = tc.constraint_name AND ccu.constraint_schema = tc.constraint_schema
        WHERE tc.table_schema = p_schema AND tc.table_name = c.relname
          AND tc.constraint_type = 'FOREIGN KEY'
      )
    ) AS tbl
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    LEFT JOIN pg_description d ON d.objoid = c.oid AND d.objsubid = 0
    WHERE n.nspname = p_schema AND c.relkind = 'r'
  ) sub;
$function$;
COMMENT ON FUNCTION pgv.schema_discover(text) IS 'Returns complete schema structure: tables with columns, FK relations, comments, row counts.';

CREATE OR REPLACE FUNCTION pgv.schema_inspect(p_schema text, p_entity text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_out text := '';
  v_table_oid oid;
  v_table_comment text;
  v_rec record;
  v_pk_cols text[];
  v_fk_cols text[];
  v_crud_names text[] := ARRAY[
    p_entity || '_create', p_entity || '_read', p_entity || '_load',
    p_entity || '_list', p_entity || '_update', p_entity || '_delete'
  ];
  v_has_section boolean;
  v_type_display text;
  v_flags text;
BEGIN
  -- Resolve table OID
  SELECT c.oid, d.description INTO v_table_oid, v_table_comment
  FROM pg_class c
  JOIN pg_namespace n ON n.oid = c.relnamespace
  LEFT JOIN pg_description d ON d.objoid = c.oid AND d.objsubid = 0
  WHERE n.nspname = p_schema AND c.relname = p_entity AND c.relkind = 'r';

  IF v_table_oid IS NULL THEN
    RETURN format('entity %I.%I not found', p_schema, p_entity);
  END IF;

  -- Header
  v_out := '## ' || p_entity || chr(10);
  IF v_table_comment IS NOT NULL THEN
    v_out := v_out || v_table_comment || chr(10);
  END IF;

  -- Get PK columns
  SELECT array_agg(a.attname) INTO v_pk_cols
  FROM pg_index ix
  JOIN pg_attribute a ON a.attrelid = ix.indrelid AND a.attnum = ANY(ix.indkey)
  WHERE ix.indrelid = v_table_oid AND ix.indisprimary;

  -- Get FK columns
  SELECT array_agg(a.attname) INTO v_fk_cols
  FROM pg_constraint con
  JOIN pg_attribute a ON a.attrelid = con.conrelid AND a.attnum = ANY(con.conkey)
  WHERE con.conrelid = v_table_oid AND con.contype = 'f';

  -- Attributes section
  v_out := v_out || chr(10) || 'attributes:' || chr(10);
  FOR v_rec IN
    SELECT a.attname, t.typname, a.attnotnull, d.description
    FROM pg_attribute a
    JOIN pg_type t ON t.oid = a.atttypid
    LEFT JOIN pg_description d ON d.objoid = v_table_oid AND d.objsubid = a.attnum
    WHERE a.attrelid = v_table_oid AND a.attnum > 0 AND NOT a.attisdropped
    ORDER BY
      CASE WHEN a.attname = ANY(coalesce(v_pk_cols, '{}')) THEN 0
           WHEN a.attname = ANY(coalesce(v_fk_cols, '{}')) THEN 1
           WHEN a.attnotnull THEN 2
           ELSE 3 END,
      a.attnum
  LOOP
    -- Format type
    v_type_display := v_rec.typname;
    IF v_type_display LIKE '\_%' THEN
      v_type_display := substr(v_type_display, 2) || '[]';
    END IF;

    -- Flags
    v_flags := '';
    IF v_rec.attname = ANY(coalesce(v_pk_cols, '{}')) THEN
      v_flags := 'PK';
    ELSIF v_rec.attname = ANY(coalesce(v_fk_cols, '{}')) THEN
      v_flags := 'FK';
    ELSIF v_rec.attnotnull THEN
      v_flags := 'NOT NULL';
    END IF;

    v_out := v_out || '  ' || rpad(v_rec.attname, 22) || rpad(v_type_display, 14) || rpad(v_flags, 10);
    IF v_rec.description IS NOT NULL THEN
      v_out := v_out || v_rec.description;
    END IF;
    v_out := v_out || chr(10);
  END LOOP;

  -- CRUD section
  v_has_section := false;
  FOR v_rec IN
    SELECT p.proname, pg_get_function_arguments(p.oid) AS args,
           t.typname AS rettype, d.description,
           p.proretset
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    JOIN pg_type t ON t.oid = p.prorettype
    LEFT JOIN pg_description d ON d.objoid = p.oid
    WHERE n.nspname = p_schema
      AND p.proname IN (
        p_entity || '_create', p_entity || '_read', p_entity || '_load',
        p_entity || '_list', p_entity || '_update', p_entity || '_delete'
      )
      AND p.proconfig @> ARRAY['api.expose=mcp']
    ORDER BY array_position(v_crud_names, p.proname)
  LOOP
    IF NOT v_has_section THEN
      v_out := v_out || chr(10) || 'crud:' || chr(10);
      v_has_section := true;
    END IF;
    v_out := v_out || '  ' || v_rec.proname || '(' || coalesce(v_rec.args, '') || ')';
    IF v_rec.proretset THEN
      v_out := v_out || ' -> SETOF ' || v_rec.rettype;
    ELSE
      v_out := v_out || ' -> ' || v_rec.rettype;
    END IF;
    IF v_rec.description IS NOT NULL THEN
      v_out := v_out || '  — ' || v_rec.description;
    END IF;
    v_out := v_out || chr(10);
  END LOOP;

  -- Methods section
  v_has_section := false;
  FOR v_rec IN
    SELECT p.proname, pg_get_function_arguments(p.oid) AS args,
           t.typname AS rettype, d.description,
           p.proretset
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    JOIN pg_type t ON t.oid = p.prorettype
    LEFT JOIN pg_description d ON d.objoid = p.oid
    WHERE n.nspname = p_schema
      AND p.proname LIKE p_entity || '_%'
      AND p.proname NOT IN (
        p_entity || '_create', p_entity || '_read', p_entity || '_load',
        p_entity || '_list', p_entity || '_update', p_entity || '_delete'
      )
      AND p.proconfig @> ARRAY['api.expose=mcp']
    ORDER BY p.proname
  LOOP
    IF NOT v_has_section THEN
      v_out := v_out || chr(10) || 'methods:' || chr(10);
      v_has_section := true;
    END IF;
    v_out := v_out || '  ' || v_rec.proname || '(' || coalesce(v_rec.args, '') || ')';
    IF v_rec.proretset THEN
      v_out := v_out || ' -> SETOF ' || v_rec.rettype;
    ELSE
      v_out := v_out || ' -> ' || v_rec.rettype;
    END IF;
    IF v_rec.description IS NOT NULL THEN
      v_out := v_out || '  — ' || v_rec.description;
    END IF;
    v_out := v_out || chr(10);
  END LOOP;

  -- Relations section (incoming FK)
  v_has_section := false;
  FOR v_rec IN
    SELECT c1.relname AS source_table, a1.attname AS source_col, d.description
    FROM pg_constraint con
    JOIN pg_class c1 ON c1.oid = con.conrelid
    JOIN pg_attribute a1 ON a1.attrelid = con.conrelid AND a1.attnum = con.conkey[1]
    LEFT JOIN pg_description d ON d.objoid = c1.oid AND d.objsubid = 0
    WHERE con.confrelid = v_table_oid AND con.contype = 'f'
    ORDER BY c1.relname
  LOOP
    IF NOT v_has_section THEN
      v_out := v_out || chr(10) || 'relations:' || chr(10);
      v_has_section := true;
    END IF;
    v_out := v_out || '  ' || v_rec.source_table || ' -> ' || v_rec.source_col || ' FK';
    IF v_rec.description IS NOT NULL THEN
      v_out := v_out || '  — ' || v_rec.description;
    END IF;
    v_out := v_out || chr(10);
  END LOOP;

  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION pgv.schema_inspect(text,text) IS 'Full entity discovery in LMNAV text: attributes, CRUD functions, custom methods with args, incoming FK relations.';

CREATE OR REPLACE FUNCTION pgv.schema_table(p_schema text, p_table text)
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_object(
    'schema', p_schema,
    'table', p_table,
    'comment', (
      SELECT d.description FROM pg_description d
      JOIN pg_class c ON c.oid = d.objoid
      JOIN pg_namespace n ON n.oid = c.relnamespace
      WHERE n.nspname = p_schema AND c.relname = p_table AND d.objsubid = 0
    ),
    'columns', (
      SELECT coalesce(jsonb_agg(
        jsonb_build_object(
          'name', col.column_name,
          'type', col.udt_name || CASE
            WHEN col.character_maximum_length IS NOT NULL THEN '(' || col.character_maximum_length || ')'
            ELSE '' END,
          'nullable', col.is_nullable = 'YES',
          'default', col.column_default,
          'comment', (
            SELECT d.description FROM pg_description d
            JOIN pg_class c ON c.oid = d.objoid
            JOIN pg_namespace n ON n.oid = c.relnamespace
            JOIN pg_attribute a ON a.attrelid = c.oid AND a.attnum = d.objsubid
            WHERE n.nspname = p_schema AND c.relname = p_table AND a.attname = col.column_name::name
          )
        ) ORDER BY col.ordinal_position
      ), '[]')
      FROM information_schema.columns col
      WHERE col.table_schema = p_schema AND col.table_name = p_table
    ),
    'check_constraints', (
      SELECT coalesce(jsonb_agg(
        jsonb_build_object(
          'name', cc.constraint_name,
          'definition', cc.check_clause
        )
      ), '[]')
      FROM information_schema.check_constraints cc
      JOIN information_schema.table_constraints tc
        ON tc.constraint_name = cc.constraint_name AND tc.constraint_schema = cc.constraint_schema
      WHERE tc.table_schema = p_schema AND tc.table_name = p_table
        AND tc.constraint_type = 'CHECK'
        AND cc.check_clause NOT LIKE '%IS NOT NULL%'
    ),
    'foreign_keys', (
      SELECT coalesce(jsonb_agg(
        jsonb_build_object(
          'column', kcu.column_name,
          'references', ccu.table_schema || '.' || ccu.table_name || '.' || ccu.column_name
        )
      ), '[]')
      FROM information_schema.table_constraints tc
      JOIN information_schema.key_column_usage kcu
        ON kcu.constraint_name = tc.constraint_name AND kcu.table_schema = tc.table_schema
      JOIN information_schema.constraint_column_usage ccu
        ON ccu.constraint_name = tc.constraint_name AND ccu.constraint_schema = tc.constraint_schema
      WHERE tc.table_schema = p_schema AND tc.table_name = p_table
        AND tc.constraint_type = 'FOREIGN KEY'
    ),
    'indexes', (
      SELECT coalesce(jsonb_agg(
        jsonb_build_object(
          'name', i.relname,
          'unique', ix.indisunique,
          'columns', (
            SELECT jsonb_agg(a.attname ORDER BY k.ord)
            FROM unnest(ix.indkey) WITH ORDINALITY AS k(attnum, ord)
            JOIN pg_attribute a ON a.attrelid = ix.indrelid AND a.attnum = k.attnum
          )
        )
      ), '[]')
      FROM pg_index ix
      JOIN pg_class t ON t.oid = ix.indrelid
      JOIN pg_class i ON i.oid = ix.indexrelid
      JOIN pg_namespace n ON n.oid = t.relnamespace
      WHERE n.nspname = p_schema AND t.relname = p_table
        AND NOT ix.indisprimary
    ),
    'rls', (
      SELECT jsonb_build_object(
        'enabled', c.relrowsecurity,
        'policies', coalesce((
          SELECT jsonb_agg(jsonb_build_object('name', pol.polname, 'permissive', pol.polpermissive))
          FROM pg_policy pol WHERE pol.polrelid = c.oid
        ), '[]')
      )
      FROM pg_class c
      JOIN pg_namespace n ON n.oid = c.relnamespace
      WHERE n.nspname = p_schema AND c.relname = p_table
    )
  );
$function$;
COMMENT ON FUNCTION pgv.schema_table(text,text) IS 'Returns detailed table structure: columns, CHECK constraints, FK, indexes, RLS policies.';

CREATE OR REPLACE FUNCTION pgv.route_crud(p_verb text, p_uri text, p_data jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_parsed jsonb;
  v_schema text;
  v_entity text;
  v_id text;
  v_method text;
  v_filter text;
  v_fragment text;
  v_fn text;
  v_fn_fallback text;
  v_result jsonb;
  v_actions jsonb := '[]';
  v_verb text := lower(p_verb);
  v_is_jsonb boolean;
BEGIN
  v_parsed := pgv._parse_uri(p_uri);
  v_schema := v_parsed->>'schema';
  v_entity := v_parsed->>'entity';
  v_id := v_parsed->>'id';
  v_method := v_parsed->>'method';
  v_filter := v_parsed->>'filter';
  v_fragment := v_parsed->>'fragment';

  -- get :// → catalog
  IF v_schema IS NULL AND v_entity IS NULL THEN
    RETURN jsonb_build_object('data', pgv.schema_catalog(), 'uri', p_uri);
  END IF;

  IF NOT EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = v_schema) THEN
    RETURN jsonb_build_object('error', 'not_found', 'message', format('schema "%s" does not exist', v_schema));
  END IF;

  IF v_entity IS NULL THEN
    RETURN jsonb_build_object('data', pgv.schema_discover(v_schema), 'uri', p_uri);
  END IF;

  IF v_fragment = 'schema' THEN
    RETURN jsonb_build_object('data', pgv.schema_table(v_schema, v_entity), 'uri', p_uri);
  END IF;

  CASE v_verb
    WHEN 'get' THEN
      IF v_id IS NOT NULL THEN
        v_fn := v_entity || '_read';
        v_fn_fallback := v_entity || '_load';
        IF NOT EXISTS (SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = v_schema AND p.proname = v_fn) THEN
          v_fn := v_fn_fallback;
        END IF;
        IF NOT EXISTS (SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = v_schema AND p.proname = v_fn) THEN
          RETURN jsonb_build_object('error', 'not_found', 'message', format('function %s.%s_read() does not exist', v_schema, v_entity));
        END IF;
        -- Check if function returns jsonb directly
        SELECT t.typname = 'jsonb' INTO v_is_jsonb
        FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace JOIN pg_type t ON t.oid = p.prorettype
        WHERE n.nspname = v_schema AND p.proname = v_fn;
        IF v_is_jsonb THEN
          EXECUTE format('SELECT %I.%I(%L)', v_schema, v_fn, v_id) INTO v_result;
        ELSE
          EXECUTE format('SELECT to_jsonb(r) FROM %I.%I(%L) r', v_schema, v_fn, v_id) INTO v_result;
        END IF;
      ELSE
        v_fn := v_entity || '_list';
        IF NOT EXISTS (SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = v_schema AND p.proname = v_fn) THEN
          RETURN jsonb_build_object('error', 'not_found', 'message', format('function %s.%s() does not exist', v_schema, v_fn));
        END IF;
        IF v_filter IS NOT NULL THEN
          EXECUTE format('SELECT coalesce(jsonb_agg(t), ''[]''::jsonb) FROM %I.%I(%L) t', v_schema, v_fn, v_filter) INTO v_result;
        ELSE
          EXECUTE format('SELECT coalesce(jsonb_agg(t), ''[]''::jsonb) FROM %I.%I() t', v_schema, v_fn) INTO v_result;
        END IF;
      END IF;

    WHEN 'set' THEN
      v_fn := v_entity || '_create';
      IF NOT EXISTS (SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = v_schema AND p.proname = v_fn) THEN
        RETURN jsonb_build_object('error', 'not_found', 'message', format('function %s.%s() does not exist', v_schema, v_fn));
      END IF;
      SELECT t.typname = 'jsonb' INTO v_is_jsonb
      FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace JOIN pg_type t ON t.oid = p.prorettype
      WHERE n.nspname = v_schema AND p.proname = v_fn;
      IF v_is_jsonb THEN
        EXECUTE format('SELECT %I.%I(jsonb_populate_record(NULL::%I.%I, $1))', v_schema, v_fn, v_schema, v_entity) USING p_data INTO v_result;
      ELSE
        EXECUTE format('SELECT to_jsonb(r) FROM %I.%I(jsonb_populate_record(NULL::%I.%I, $1)) r', v_schema, v_fn, v_schema, v_entity) USING p_data INTO v_result;
      END IF;

    WHEN 'patch' THEN
      v_fn := v_entity || '_update';
      IF NOT EXISTS (SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = v_schema AND p.proname = v_fn) THEN
        RETURN jsonb_build_object('error', 'not_found', 'message', format('function %s.%s() does not exist', v_schema, v_fn));
      END IF;
      SELECT t.typname = 'jsonb' INTO v_is_jsonb
      FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace JOIN pg_type t ON t.oid = p.prorettype
      WHERE n.nspname = v_schema AND p.proname = v_fn;
      IF EXISTS (
        SELECT 1 FROM pg_attribute a JOIN pg_class c ON c.oid = a.attrelid JOIN pg_namespace n ON n.oid = c.relnamespace
        WHERE n.nspname = v_schema AND c.relname = v_entity AND a.attname = 'slug' AND a.attnum > 0 AND NOT a.attisdropped
      ) THEN
        IF v_is_jsonb THEN
          EXECUTE format('SELECT %I.%I(jsonb_populate_record(NULL::%I.%I, $1))', v_schema, v_fn, v_schema, v_entity) USING p_data || jsonb_build_object('slug', v_id) INTO v_result;
        ELSE
          EXECUTE format('SELECT to_jsonb(r) FROM %I.%I(jsonb_populate_record(NULL::%I.%I, $1)) r', v_schema, v_fn, v_schema, v_entity) USING p_data || jsonb_build_object('slug', v_id) INTO v_result;
        END IF;
      ELSE
        IF v_is_jsonb THEN
          EXECUTE format('SELECT %I.%I(jsonb_populate_record(NULL::%I.%I, $1))', v_schema, v_fn, v_schema, v_entity) USING p_data || jsonb_build_object('id', v_id) INTO v_result;
        ELSE
          EXECUTE format('SELECT to_jsonb(r) FROM %I.%I(jsonb_populate_record(NULL::%I.%I, $1)) r', v_schema, v_fn, v_schema, v_entity) USING p_data || jsonb_build_object('id', v_id) INTO v_result;
        END IF;
      END IF;

    WHEN 'delete' THEN
      v_fn := v_entity || '_delete';
      IF NOT EXISTS (SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = v_schema AND p.proname = v_fn) THEN
        RETURN jsonb_build_object('error', 'not_found', 'message', format('function %s.%s() does not exist', v_schema, v_fn));
      END IF;
      SELECT t.typname = 'jsonb' INTO v_is_jsonb
      FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace JOIN pg_type t ON t.oid = p.prorettype
      WHERE n.nspname = v_schema AND p.proname = v_fn;
      IF v_is_jsonb THEN
        EXECUTE format('SELECT %I.%I(%L)', v_schema, v_fn, v_id) INTO v_result;
      ELSE
        EXECUTE format('SELECT to_jsonb(r) FROM %I.%I(%L) r', v_schema, v_fn, v_id) INTO v_result;
      END IF;

    WHEN 'post' THEN
      IF v_method IS NULL THEN
        RETURN jsonb_build_object('error', 'bad_request', 'message', 'POST requires a method in the URI');
      END IF;
      v_fn := v_entity || '_' || v_method;
      IF NOT EXISTS (SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = v_schema AND p.proname = v_fn) THEN
        RETURN jsonb_build_object('error', 'not_found', 'message', format('function %s.%s() does not exist', v_schema, v_fn));
      END IF;
      SELECT t.typname = 'jsonb' INTO v_is_jsonb
      FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace JOIN pg_type t ON t.oid = p.prorettype
      WHERE n.nspname = v_schema AND p.proname = v_fn;
      IF v_id IS NOT NULL AND p_data IS NOT NULL THEN
        IF v_is_jsonb THEN
          EXECUTE format('SELECT %I.%I(%L, %L::jsonb)', v_schema, v_fn, v_id, p_data::text) INTO v_result;
        ELSE
          EXECUTE format('SELECT to_jsonb(r) FROM %I.%I(%L, %L::jsonb) r', v_schema, v_fn, v_id, p_data::text) INTO v_result;
        END IF;
      ELSIF v_id IS NOT NULL THEN
        IF v_is_jsonb THEN
          EXECUTE format('SELECT %I.%I(%L)', v_schema, v_fn, v_id) INTO v_result;
        ELSE
          EXECUTE format('SELECT to_jsonb(r) FROM %I.%I(%L) r', v_schema, v_fn, v_id) INTO v_result;
        END IF;
      ELSE
        IF v_is_jsonb THEN
          EXECUTE format('SELECT %I.%I()', v_schema, v_fn) INTO v_result;
        ELSE
          EXECUTE format('SELECT to_jsonb(r) FROM %I.%I() r', v_schema, v_fn) INTO v_result;
        END IF;
      END IF;

    ELSE
      RETURN jsonb_build_object('error', 'bad_request', 'message', format('unsupported verb "%s"', p_verb));
  END CASE;

  -- HATEOAS: extract actions from _read() response (module is responsible)
  IF v_result IS NOT NULL AND v_result ? 'actions' THEN
    v_actions := v_result->'actions';
    v_result := v_result - 'actions';
  END IF;

  RETURN jsonb_build_object(
    'data', coalesce(v_result, 'null'::jsonb),
    'uri', p_uri,
    'actions', v_actions
  );
END;
$function$;
COMMENT ON FUNCTION pgv.route_crud(text,text,jsonb) IS 'CRUD router: dispatch get/set/patch/delete/post via URI. Returns {data, uri, actions, view?}. Handles jsonb and record return types.';

CREATE OR REPLACE FUNCTION pgv.slugify(VARIADIC p_parts text[])
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_raw text;
  v_slug text;
BEGIN
  -- Concat non-null parts with space
  SELECT string_agg(p, ' ') INTO v_raw
  FROM unnest(p_parts) AS p
  WHERE p IS NOT NULL AND trim(p) != '';

  IF v_raw IS NULL THEN RETURN ''; END IF;

  v_slug := lower(v_raw);

  -- Unaccent via extension if available, else manual translate
  BEGIN
    v_slug := unaccent(v_slug);
  EXCEPTION WHEN undefined_function THEN
    v_slug := translate(v_slug,
      'éèêëàâäùûüïîôöçœæñ',
      'eeeeaaauuuiioocoanh');
  END;

  -- Replace non-alphanumeric with dash
  v_slug := regexp_replace(v_slug, '[^a-z0-9]+', '-', 'g');

  -- Trim dashes
  v_slug := trim(BOTH '-' FROM v_slug);

  RETURN v_slug;
END;
$function$;
COMMENT ON FUNCTION pgv.slugify(text[]) IS 'Generate URL-safe slug from 1..N text segments. Handles accents, punctuation, multiple dashes.';

CREATE OR REPLACE FUNCTION pgv.t(p_key text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_lang text;
  v_value text;
BEGIN
  v_lang := coalesce(nullif(current_setting('pgv.lang', true), ''), 'fr');

  SELECT value INTO v_value FROM pgv.i18n WHERE lang = v_lang AND key = p_key;
  IF FOUND THEN RETURN v_value; END IF;

  -- Fallback to French if different lang
  IF v_lang <> 'fr' THEN
    SELECT value INTO v_value FROM pgv.i18n WHERE lang = 'fr' AND key = p_key;
    IF FOUND THEN RETURN v_value; END IF;
  END IF;

  -- Return key itself as last resort
  RETURN p_key;
END;
$function$;
COMMENT ON FUNCTION pgv.t(text) IS 'i18n translation lookup. Returns translated value or the key itself as fallback.';

CREATE OR REPLACE FUNCTION pgv.post_issue_report(p jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_desc text;
  v_type text;
  v_module text;
  v_ctx  jsonb;
BEGIN
  v_desc := trim(p->>'description');
  IF v_desc IS NULL OR v_desc = '' THEN
    RETURN pgv.toast(pgv.t('issue.error'), 'error');
  END IF;

  v_type := coalesce(p->>'issue_type', 'bug');
  IF v_type NOT IN ('bug', 'enhancement', 'question') THEN
    v_type := 'bug';
  END IF;

  v_module := p->>'schema';

  -- Build context from remaining keys
  v_ctx := p - 'description' - 'issue_type' - 'schema';

  INSERT INTO workbench.issue_report (description, issue_type, module, context)
  VALUES (v_desc, v_type, v_module, v_ctx);

  RETURN pgv.toast(pgv.t('issue.success'));
END;
$function$;
COMMENT ON FUNCTION pgv.post_issue_report(jsonb) IS 'Receive an issue report (bug/enhancement/question) from the shell UI and store it in workbench.issue_report';

CREATE OR REPLACE FUNCTION pgv.ui_action(p_label text, p_verb text, p_uri text, p_variant text DEFAULT NULL::text, p_confirm text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('type', 'action', 'label', p_label, 'verb', p_verb, 'uri', p_uri)
    || CASE WHEN p_variant IS NOT NULL THEN jsonb_build_object('variant', p_variant) ELSE '{}'::jsonb END
    || CASE WHEN p_confirm IS NOT NULL THEN jsonb_build_object('confirm', p_confirm) ELSE '{}'::jsonb END;
$function$;
COMMENT ON FUNCTION pgv.ui_action(text,text,text,text,text) IS 'SDUI interactive: action button triggering route_crud (verb + uri)';

CREATE OR REPLACE FUNCTION pgv.ui_badge(p_text text, p_variant text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
