    || CASE WHEN p_variant IS NOT NULL THEN jsonb_build_object('variant', p_variant) ELSE '{}'::jsonb END;
$function$;
COMMENT ON FUNCTION pgv.ui_badge(text,text) IS 'SDUI primitive: colored badge (status, category). Variant: success, warning, error, info, or hex color.';

CREATE OR REPLACE FUNCTION pgv.ui_card(p_entity_uri text, p_level text, p_header jsonb, p_body jsonb DEFAULT NULL::jsonb, p_related jsonb DEFAULT NULL::jsonb, p_actions jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object(
    'type', 'card',
    'entity_uri', p_entity_uri,
    'level', p_level,
    'header', p_header
  )
  || CASE WHEN p_body IS NOT NULL THEN jsonb_build_object('body', p_body) ELSE '{}'::jsonb END
  || CASE WHEN p_related IS NOT NULL THEN jsonb_build_object('related', p_related) ELSE '{}'::jsonb END
  || CASE WHEN p_actions IS NOT NULL THEN jsonb_build_object('actions', p_actions) ELSE '{}'::jsonb END;
$function$;
COMMENT ON FUNCTION pgv.ui_card(text,text,jsonb,jsonb,jsonb,jsonb) IS 'SDUI entity card at 3 detail levels: compact (inline), standard (header+body+related), expanded (full+actions).';

CREATE OR REPLACE FUNCTION pgv.ui_card_header(p_icon text, p_title text, VARIADIC p_badges jsonb[] DEFAULT '{}'::jsonb[])
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('icon', p_icon, 'title', p_title)
    || CASE WHEN array_length(p_badges, 1) > 0
         THEN jsonb_build_object('badges', array_to_json(p_badges)::jsonb)
         ELSE '{}'::jsonb END;
$function$;
COMMENT ON FUNCTION pgv.ui_card_header(text,text,jsonb[]) IS 'SDUI card header: icon + title + optional badges. Reusable across all card levels.';

CREATE OR REPLACE FUNCTION pgv.ui_col(p_key text, p_label text, p_cell jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('key', p_key, 'label', p_label) 
    || CASE WHEN p_cell IS NOT NULL THEN jsonb_build_object('cell', p_cell) ELSE '{}'::jsonb END;
$function$;
COMMENT ON FUNCTION pgv.ui_col(text,text,jsonb) IS 'SDUI helper: table column definition with optional cell renderer type';

CREATE OR REPLACE FUNCTION pgv.ui_color(p_value text)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('type', 'color', 'value', p_value);
$function$;
COMMENT ON FUNCTION pgv.ui_color(text) IS 'SDUI primitive: color swatch with hex preview';

CREATE OR REPLACE FUNCTION pgv.ui_column(VARIADIC p_children jsonb[])
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('type', 'column', 'children', array_to_json(p_children)::jsonb);
$function$;
COMMENT ON FUNCTION pgv.ui_column(jsonb[]) IS 'SDUI layout: vertical stack of children';

CREATE OR REPLACE FUNCTION pgv.ui_currency(p_amount numeric, p_currency text DEFAULT 'EUR'::text)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('type', 'currency', 'amount', p_amount, 'currency', p_currency);
$function$;
COMMENT ON FUNCTION pgv.ui_currency(numeric,text) IS 'SDUI currency: locale-aware amount with currency code. Red for negative.';

CREATE OR REPLACE FUNCTION pgv.ui_datasource(p_uri text, p_page_size integer DEFAULT 20, p_searchable boolean DEFAULT false, p_default_sort text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('uri', p_uri, 'page_size', p_page_size, 'searchable', p_searchable)
    || CASE WHEN p_default_sort IS NOT NULL THEN jsonb_build_object('default_sort', p_default_sort) ELSE '{}'::jsonb END;
$function$;
COMMENT ON FUNCTION pgv.ui_datasource(text,integer,boolean,text) IS 'SDUI datasource definition: URI endpoint + pagination/search config';

CREATE OR REPLACE FUNCTION pgv.ui_detail(p_source text, p_fields jsonb)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('type', 'detail', 'source', p_source, 'fields', p_fields);
$function$;
COMMENT ON FUNCTION pgv.ui_detail(text,jsonb) IS 'SDUI connected component: key/value detail view bound to a datasource';

CREATE OR REPLACE FUNCTION pgv.ui_field(p_key text, p_type text, p_label text, p_required boolean DEFAULT false, p_options jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('type', 'field', 'key', p_key, 'fieldType', p_type, 'label', p_label, 'required', p_required)
    || CASE WHEN p_options IS NOT NULL THEN jsonb_build_object('options', p_options) ELSE '{}'::jsonb END;
$function$;
COMMENT ON FUNCTION pgv.ui_field(text,text,text,boolean,jsonb) IS 'SDUI form field: text, email, tel, number, date, select, textarea, checkbox';

CREATE OR REPLACE FUNCTION pgv.ui_form(p_uri text, p_verb text, p_fields jsonb)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT jsonb_build_object('type', 'form', 'uri', p_uri, 'verb', p_verb, 'fields', p_fields);
$function$;
COMMENT ON FUNCTION pgv.ui_form(text,text,jsonb) IS 'SDUI form: submit to route_crud(verb, uri) with field values. Fields is array of ui_field/ui_section/ui_row.';

CREATE OR REPLACE FUNCTION pgv.ui_form_for(p_schema text, p_entity text, p_verb text DEFAULT 'set'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_fields jsonb[] := '{}';
  v_rec record;
  v_field_type text;
  v_label text;
  v_required boolean;
  v_options jsonb;
  v_skip text[] := ARRAY['id', 'tenant_id', 'created_at', 'updated_at', 'slug', 'search_vec'];
BEGIN
  FOR v_rec IN
    SELECT a.attname, t.typname, a.attnotnull,
           d.description AS col_comment,
           -- FK info
           (SELECT n2.nspname FROM pg_constraint con
            JOIN pg_class c2 ON c2.oid = con.confrelid
            JOIN pg_namespace n2 ON n2.oid = c2.relnamespace
            WHERE con.conrelid = c.oid AND con.contype = 'f'
              AND a.attnum = ANY(con.conkey)
            LIMIT 1) AS fk_schema,
           (SELECT c2.relname FROM pg_constraint con
            JOIN pg_class c2 ON c2.oid = con.confrelid
            WHERE con.conrelid = c.oid AND con.contype = 'f'
              AND a.attnum = ANY(con.conkey)
            LIMIT 1) AS fk_table
    FROM pg_attribute a
    JOIN pg_class c ON c.oid = a.attrelid
    JOIN pg_namespace n ON n.oid = c.relnamespace
    JOIN pg_type t ON t.oid = a.atttypid
    LEFT JOIN pg_description d ON d.objoid = c.oid AND d.objsubid = a.attnum
    WHERE n.nspname = p_schema AND c.relname = p_entity
      AND a.attnum > 0 AND NOT a.attisdropped
      AND a.attname != ALL(v_skip)
    ORDER BY a.attnum
  LOOP
    -- Map PG type to SDUI field type
    v_options := NULL;

    IF v_rec.fk_table IS NOT NULL THEN
      v_field_type := 'select';
      -- FK select: options loaded from datasource
      v_options := jsonb_build_object(
        'source', v_rec.fk_schema || '://' || v_rec.fk_table
      );
    ELSIF v_rec.typname IN ('int2', 'int4', 'int8', 'float4', 'float8', 'numeric') THEN
      v_field_type := 'number';
    ELSIF v_rec.typname = 'bool' THEN
      v_field_type := 'checkbox';
    ELSIF v_rec.typname IN ('timestamptz', 'timestamp', 'date') THEN
      v_field_type := 'date';
    ELSIF v_rec.typname = 'jsonb' THEN
      v_field_type := 'textarea';
    ELSIF v_rec.typname LIKE '\_text' OR v_rec.typname LIKE '\_%' THEN
      v_field_type := 'textarea';
    ELSE
      v_field_type := 'text';
    END IF;

    -- Label: COMMENT ON COLUMN or column name humanized
    v_label := coalesce(v_rec.col_comment, replace(v_rec.attname, '_', ' '));

    -- Required: NOT NULL and not a boolean (booleans default to false)
    v_required := v_rec.attnotnull AND v_rec.typname != 'bool';

    v_fields := v_fields || pgv.ui_field(v_rec.attname, v_field_type, v_label, v_required, v_options);
  END LOOP;

  RETURN pgv.ui_form(
    p_schema || '://' || p_entity,
    p_verb,
    array_to_json(v_fields)::jsonb
  );
END;
$function$;
COMMENT ON FUNCTION pgv.ui_form_for(text,text,text) IS 'Auto-generate SDUI form by introspecting pg_attribute/pg_type/pg_constraint for a schema.entity. Maps PG types to field types, resolves FK to select, excludes auto columns.';

