CREATE OR REPLACE FUNCTION pgv.view_schema()
 RETURNS json
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '{
    "type": "object",
    "required": ["uri", "label", "template"],
    "additionalProperties": false,
    "properties": {
      "uri": { "type": "string", "pattern": "^[a-z_]+://[a-z_]+$" },
      "icon": { "type": "string" },
      "label": { "type": "string", "pattern": "^[a-z_]+\\." },
      "readonly": { "type": "boolean" },
      "entity_type": { "type": "string", "enum": ["crud", "event"] },

      "template": {
        "type": "object",
        "required": ["compact", "standard"],
        "additionalProperties": false,
        "properties": {

          "compact": {
            "type": "object",
            "required": ["fields"],
            "additionalProperties": false,
            "properties": {
              "fields": { "type": "array", "minItems": 1, "items": { "oneOf": [{ "type": "string" }, { "type": "object", "required": ["key"], "properties": { "key": { "type": "string" }, "type": { "type": "string", "enum": ["text","date","datetime","currency","number","status","email","tel"] }, "label": { "type": "string", "pattern": "^[a-z_]+\\." } } }] } }
            }
          },

          "standard": {
            "type": "object",
            "required": ["fields"],
            "additionalProperties": false,
            "properties": {
              "fields": { "type": "array", "minItems": 1, "items": { "oneOf": [{ "type": "string" }, { "type": "object", "required": ["key"], "properties": { "key": { "type": "string" }, "type": { "type": "string", "enum": ["text","date","datetime","currency","number","status","email","tel"] }, "label": { "type": "string", "pattern": "^[a-z_]+\\." } } }] } },
              "stats": {
                "type": "array",
                "items": {
                  "type": "object",
                  "required": ["key", "label"],
                  "properties": {
                    "key": { "type": "string" },
                    "label": { "type": "string", "pattern": "^[a-z_]+\\." },
                    "variant": { "type": "string" }
                  }
                }
              },
              "related": {
                "type": "array",
                "items": {
                  "type": "object",
                  "required": ["entity", "label", "filter"],
                  "properties": {
                    "entity": { "type": "string", "pattern": "^[a-z_]+://[a-z_]+$" },
                    "label": { "type": "string", "pattern": "^[a-z_]+\\." },
                    "filter": { "type": "string" }
                  }
                }
              }
            }
          },

          "expanded": {
            "type": "object",
            "required": ["fields"],
            "additionalProperties": false,
            "properties": {
              "fields": { "type": "array", "minItems": 1, "items": { "oneOf": [{ "type": "string" }, { "type": "object", "required": ["key"], "properties": { "key": { "type": "string" }, "type": { "type": "string", "enum": ["text","date","datetime","currency","number","status","email","tel"] }, "label": { "type": "string", "pattern": "^[a-z_]+\\." } } }] } },
              "stats": {
                "type": "array",
                "items": {
                  "type": "object",
                  "required": ["key", "label"],
                  "properties": {
                    "key": { "type": "string" },
                    "label": { "type": "string", "pattern": "^[a-z_]+\\." },
                    "variant": { "type": "string" }
                  }
                }
              },
              "related": {
                "type": "array",
                "items": {
                  "type": "object",
                  "required": ["entity", "label", "filter"],
                  "properties": {
                    "entity": { "type": "string", "pattern": "^[a-z_]+://[a-z_]+$" },
                    "label": { "type": "string", "pattern": "^[a-z_]+\\." },
                    "filter": { "type": "string" }
                  }
                }
              }
            }
          },

          "form": {
            "type": "object",
            "required": ["sections"],
            "additionalProperties": false,
            "properties": {
              "sections": {
                "type": "array",
                "minItems": 1,
                "items": {
                  "type": "object",
                  "required": ["label", "fields"],
                  "additionalProperties": false,
                  "properties": {
                    "label": { "type": "string", "pattern": "^[a-z_]+\\." },
                    "fields": {
                      "type": "array",
                      "minItems": 1,
                      "items": {
                        "type": "object",
                        "required": ["key", "type", "label"],
                        "properties": {
                          "key": { "type": "string" },
                          "type": { "type": "string", "enum": ["text", "email", "tel", "number", "date", "select", "textarea", "checkbox", "combobox"] },
                          "label": { "type": "string", "pattern": "^[a-z_]+\\." },
                          "required": { "type": "boolean" },
                          "options": {},
                          "source": { "type": "string" },
                          "display": { "type": "string" },
                          "filter": { "type": "string" }
                        }
                      }
                    }
                  }
                }
              }
            }
          }

        }
      },

      "actions": {
        "type": "object",
        "additionalProperties": {
          "type": "object",
          "required": ["label"],
          "properties": {
            "label": { "type": "string", "pattern": "^[a-z_]+\\." },
            "icon": { "type": "string" },
            "variant": { "type": "string", "enum": ["default", "primary", "warning", "danger", "muted"] },
            "confirm": { "type": "string", "pattern": "^[a-z_]+\\." }
          }
        }
      }

    }
  }'::json;
$function$;
COMMENT ON FUNCTION pgv.view_schema() IS 'JSON Schema for the _view() contract. Used by route_crud to validate entity templates.';

CREATE OR REPLACE FUNCTION pgv.check_view(p_schema text, p_entity text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_fn text := p_entity || '_view';
  v_result jsonb;
  v_valid boolean;
BEGIN
  -- Check function exists
  IF NOT EXISTS (
    SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = p_schema AND p.proname = v_fn
  ) THEN
    RETURN jsonb_build_object('valid', false, 'errors', jsonb_build_array('function ' || p_schema || '.' || v_fn || '() does not exist'));
  END IF;

  -- Call the view function
  EXECUTE format('SELECT %I.%I()', p_schema, v_fn) INTO v_result;

  -- Validate against JSON Schema
  v_valid := jsonb_matches_schema(pgv.view_schema(), v_result);

  IF v_valid THEN
    RETURN jsonb_build_object('valid', true, 'uri', v_result->>'uri');
  ELSE
    RETURN jsonb_build_object('valid', false, 'errors', jsonb_build_array('JSON Schema validation failed'), 'result', v_result);
  END IF;
END;
$function$;
COMMENT ON FUNCTION pgv.check_view(text,text) IS 'Validate that {entity}_view() output conforms to the _view() JSON Schema contract.';

GRANT USAGE ON SCHEMA pgv TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA pgv TO anon;
GRANT SELECT ON ALL TABLES IN SCHEMA pgv TO anon;
